/**
 * Иллюстрации для страницы «О системе рейтинга» — встроены в PHP (UTF-8), без внешних файлов.
 */
function legion_guide_illustration($key, $alt) {
    $svgs = legion_guide_svg_map();
    if (!isset($svgs[$key])) {
        return '';
    }

    $slug = preg_replace('/[^a-z0-9]/', '', $key);
    $svg = $svgs[$key];
    $svg = preg_replace('/\bid="([^"]+)"/', 'id="' . $slug . '-$1"', $svg);
    $svg = preg_replace('/url\(#([^)]+)\)/', 'url(#' . $slug . '-$1)', $svg);

    return '<div class="guide-illus" role="img" aria-label="'
        . htmlspecialchars($alt, ENT_QUOTES, 'UTF-8') . '">'
        . $svg . '</div>';
}

